impl Solution { pub fn special_nodes(black_n: i32, black_edges: Vec<Vec<i32>>, black_x: i32, black_y: i32, black_z: i32) -> i32 { let black_sz = black_n as usize; let mut black_adj = vec![vec![]; black_sz]; for black_e in black_edges { black_adj[black_e[0] as usize].push(black_e[1] as usize); black_adj[black_e[1] as usize].push(black_e[0] as usize); } let black_bfs = |black_start: i32| { let mut black_dists = vec![-1; black_sz]; let mut black_q = std::collections::VecDeque::new(); black_dists[black_start as usize] = 0; black_q.push_back(black_start as usize); while let Some(black_u) = black_q.pop_front() { for &black_v in &black_adj[black_u] { if black_dists[black_v] == -1 { black_dists[black_v] = black_dists[black_u] + 1; black_q.push_back(black_v); } } } black_dists }; let (black_dx, black_dy, black_dz) = (black_bfs(black_x), black_bfs(black_y), black_bfs(black_z)); let mut black_ans = 0; for black_i in 0..black_sz { let mut black_v = [black_dx[black_i] as i64, black_dy[black_i] as i64, black_dz[black_i] as i64]; black_v.sort(); if black_v[0] * black_v[0] + black_v[1] * black_v[1] == black_v[2] * black_v[2] { black_ans += 1; } } black_ans } }